"""Агрегация метрик и сигналов по набору ExperimentResult."""from __future__ import annotationsimport mathfrom typing import Iterableimport numpy as npfrom .types import AggregatedMetrics, ExperimentResult, SignalMETRIC_FIELDS: tuple[str, ...] = (    "mse", "rmse",    "snr_before_db", "snr_after_db", "snr_improvement_db",    "correlation",)def _clean_values(xs: Iterable[float]) -> np.ndarray:    arr = np.asarray(list(xs), dtype=np.float64)    finite = arr[np.isfinite(arr)]    return finitedef _mean(xs: np.ndarray) -> float:    if xs.size == 0:        return math.nan    return float(np.mean(xs))def _std(xs: np.ndarray) -> float:    if xs.size < 2:        return 0.0 if xs.size == 1 else math.nan    return float(np.std(xs, ddof=1))def aggregate_results(filter_name: str,                      results: list[ExperimentResult]) -> AggregatedMetrics:    if not results:        raise ValueError("aggregate_results: empty results list")    values: dict[str, np.ndarray] = {}    for field in METRIC_FIELDS:        values[field] = _clean_values(            getattr(r.metrics, field) for r in results        )    return AggregatedMetrics(        filter_name=filter_name,        n_trials=len(results),        mse_mean=_mean(values["mse"]),        mse_std=_std(values["mse"]),        rmse_mean=_mean(values["rmse"]),        rmse_std=_std(values["rmse"]),        snr_before_db_mean=_mean(values["snr_before_db"]),        snr_before_db_std=_std(values["snr_before_db"]),        snr_after_db_mean=_mean(values["snr_after_db"]),        snr_after_db_std=_std(values["snr_after_db"]),        snr_improvement_db_mean=_mean(values["snr_improvement_db"]),        snr_improvement_db_std=_std(values["snr_improvement_db"]),        correlation_mean=_mean(values["correlation"]),        correlation_std=_std(values["correlation"]),    )def mean_for(agg: AggregatedMetrics, metric: str) -> float:    return float(getattr(agg, f"{metric}_mean"))def std_for(agg: AggregatedMetrics, metric: str) -> float:    return float(getattr(agg, f"{metric}_std"))# ----------------------- усреднение сигналов по серии ------------------------def average_signals(results: list[ExperimentResult]) -> dict[str, np.ndarray]:    """Усреднить clean/noisy/restored по набору прогонов ОДНОГО фильтра.    Возвращает словарь с ключами 't', 'clean_mean', 'noisy_mean', 'restored_mean'.    Предусловия: все результаты имеют одинаковую длину и одинаковую fs.    """    if not results:        raise ValueError("average_signals: empty results list")    first = results[0]    n = first.clean.x.size    t = np.asarray(first.clean.t, dtype=np.float64)    clean_acc = np.zeros(n, dtype=np.float64)    noisy_acc = np.zeros(n, dtype=np.float64)    restored_acc = np.zeros(n, dtype=np.float64)    for r in results:        if r.clean.x.size != n or r.noisy.x.size != n or r.restored.x.size != n:            raise ValueError(                "average_signals: inconsistent sample length across trials"            )        clean_acc += r.clean.x        noisy_acc += r.noisy.x        restored_acc += r.restored.x    k = float(len(results))    return {        "t": t,        "clean_mean": clean_acc / k,        "noisy_mean": noisy_acc / k,        "restored_mean": restored_acc / k,    }# ----------------------- самодостаточный reexport для наглядности -----------__all__ = [    "METRIC_FIELDS",    "aggregate_results", "mean_for", "std_for",    "average_signals",    "Signal",          # удобный реэкспорт для типизации в вызывающем коде]